INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (189, 137021, 10, 11, '写写校园~：）', '亲爱的大家们，最近过得好不好？昨天回家的时候在路上被风吹得有点透心凉，这儿的天气终于在12月末才显露出一点冬天的感觉来，大家要多穿衣服，保重身体，好欢欢喜喜地跨过这个年去。
<br>转眼间校园开版一年多了，我竟然还能将这版主安安稳稳地做了下来。一直觉得自己是不大安定容易变化的人，能这么长久这么有热情地做一件事情，现在想来有点不可思议，当然，心里也是高兴的，因为这不多得的坚持，我陪着校园一起长大，一起历经她的成长岁月中的点滴悲欢。：）能做一个有回忆的人可是不容易的啊：（
<br>
<br>天地初开在一年多前的一个夜晚。那时我高二。和现在众多BBS上年少而又才华出众的一干DDMM比起来我可能要被笑话了，到了高二才捞到个版主做有何津津乐道的东西可言，现在我们初一初二有自己的文集自己的专栏自己的BBS甚至写出一两部震惊世人的长篇来都不为过。是的，我能说什么呢，这一年来在整个世界对那么多越来越年轻的少年写手的感叹声赞叹声惊叹声中走来，到最后落了个默默无语，转身回到这一片天地守着自己的两亩瘦田过活，基本是没什么典故好拿起来津津乐道的。
<br>唯一能讲的可能就是当上版主的那一年，2000年，我上网整整一年后的夏天。其实有些事情现在想起来真是注定的，如果不是一上网就一头扎进咖啡，不是一头扎进去后就不想再出来而是野心勃勃地到各大网站四处打打猎看是否有更大的发展前途，事情也就完全不是今天这个样子了。
<br>说到这里就有必要介绍一下自己的地方了吧：）嘿嘿~，www.cafewoo.net，一个香气四溢的好地方。如今网络充斥的各种五光十色功能强大的网站中，她吸引人的的便是她的纯文本风格，单纯清新的界面，出众的写手和不凡的文字，给人一种强烈的“家”的温馨感觉，我想她能给人这种感觉和她诞生于这个城市不无关系。厦门，那么多人口中最适合生活和爱情，最象家，最温馨的城市，大家都在出走后重新热爱她。Cafewoo，“咖啡屋”的谐音，创建她的人们在98年《第一次亲密接触》尚未如今日这般泛滥时取下的名字并沿用至今。有时候不一定要最新最与众不同，能代表过去的一个回忆一次思考一种热爱，作为一种纪念而生存，不也是很好的吗？在咖啡中讨了一块地生存，那是一年前，正是厦门的上网人数疯狂增长的时候，原来的咖啡只有“咖啡心情”一版，容纳量远远不足，就新开设了几个BBS，刚好以前开玩笑地和老大说过要过过当斑竹的瘾，这回老大找到我说给我开了个，问去不，觉得煞是新鲜，就一口应承了下来，这个版块的名字叫“菁菁校园”，要特此声明一下，名字不是我取的，到了今天我都已经懒得再为她换名字了，虽然普通得遍地都是，但是大家都叫习惯了，习惯的东西最好是不要改了，根深蒂固最好了：―）
<br>开始的时候地荒凉得半死，只有以前播在咖啡心情的几根草被转栽到这儿来了，几棵小草独自在一大片空地上孤苦伶仃地飘摇着，现在想起来有种心酸的好笑。后来情况是怎么改善的呢？我来回忆回忆先；）
<br>嗯，00年的7月是蓬勃的一月，SWEETSMALL，JOJJY，FLYICE，是一开始的时候在校园挺红的几个MM，学校的同学也来捧了场，秋叶。劲风和NPC，还有聊和VVI。秋叶是轰动人物，把一篇好贴子分了六次贴，我连给了六个精华，在校园的风头一时无两。八月的时候STRANGEGIRL来了，并留到了今天，还带了几个人往校园贡献好贴子，我妹妹听零也来了，一出手就几首诗歌，现在人远在新西兰，不知道是不是还有回来看过。这时候出现了几个神秘人物，出场贴了几篇好贴子就不见影子了，象MUMGIRL，MILU，LIUDONG，TEATEA。还有一个风云人物也要提到的，ART，和秋叶争做副斑竹，拉票投票互相抨击闹得轰轰烈烈。到了九月来了几个很厉害的MM，BIBY，CILO，SST，LIZZY，LIOO，这四个名字好象只是三个人注册的，但是我真的分不清楚了，BIBY很厉害的：），后来当了校园的推荐作者之一。偶DD也提一下，年轻人要表扬才会进步，（呼呼~~？）STOVIC，另类文学的倡导者，为了考试时作文要保持自己的风格不惜冒作文不及格的险，在取得自己不满意的成绩后还依然和老师据理力争，小伙子，有朝气啊！JJ支持你！提倡素质教育的大军有了你就有了新血液：）10月底11月的时候新人一直出现，有原来的人带的也有别的版的人来贴的，六月，XMBEAR，秋水伊人，ELVA69，宇之尘，MILKTEA，阿九（阿九算旧人了，这时候活跃些了：），`就这么走过了2000年，还挺不错的一个开始。一月的时候阿十来了，那时候名字叫Junuary（不是拼错的“一月”：）。二月的时候SWEETWHITE来了，那时候叫“挑灯看剑”，SWEET是我的小学同学，毕业后一直没联系，看了我的几篇文章后觉得我该是她的那什么时候的同学，就联系了下，后来发现果真是，我很喜欢她，她的人和文章都很好：）3月的时候五叶桔来了，她是通过我发在少年文艺上的一篇文章认识的，小我一岁的MM，很甜很漂亮，唱歌跳舞什么都行：）前阵子迷哈利迷得不行。校园的几大写手在这时候基本就定型到现在了，都是很有个性的女孩子。五月的时候SWEETWHITE的好朋友妖娆小香来了，也是不错的人：）。
<br>我们这群人从五月开始到现在，半年多的时间，历经了我们这届的高考。接着今年陪桔子和STRANGEGIRL高考，明年陪阿十。走过的都是年少的风风雨雨。相信即使岁月流长，以后将来都难忘记的，曾经有那么好的时光：）', '亲爱的大家们，最近过得好不好？昨天回家的时候在路上被风吹得有点透心凉，这儿的天气终于在12月末才显露出一点冬天的感觉来，大家要多穿衣服，保重身体，好欢欢喜喜地跨过这个年去。

转眼间校园开版一年多了，我竟然还能将这版主安安稳稳地做了下来。一直觉得自己是不大安定容易变化的人，能这么长久这么有热情地做一件事情，现在想来有点不可思议，当然，心里也是高兴的，因为这不多得的坚持，我陪着校园一起长大，一起历经她的成长岁月中的点滴悲欢。：）能做一个有回忆的人可是不容易的啊：（

天地初开在一年多前的一个夜晚。那时我高二。和现在众多BBS上年少而又才华出众的一干DDMM比起来我可能要被笑话了，到了高二才捞到个版主做有何津津乐道的东西可言，现在我们初一初二有自己的文集自己的专栏自己的BBS甚至写出一两部震惊世人的长篇来都不为过。是的，我能说什么呢，这一年来在整个世界对那么多越来越年轻的少年写手的感叹声赞叹声惊叹声中走来，到最后落了个默默无语，转身回到这一片天地守着自己的两亩瘦田过活，基本是没什么典故好拿起来津津乐道的。

